import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const API_BASE_URL = "http://127.0.0.1:5000/api";

const ProfileSetup = () => {
    const userId = localStorage.getItem('userId');
    const navigate = useNavigate();
    const [mines, setMines] = useState([]);
    const [isManual, setIsManual] = useState(false);
    
    const [formData, setFormData] = useState({
        selected_mine: '',
        mine_name: '',
        state: 'Jharkhand',
        production: '',
        employees: '',
        area: '',           // Leave empty for Synthetic Calculation
        age: '',            // Leave empty for default (5 yrs)
        plant_type: 'synthetic' // Default to State Average
    });

    useEffect(() => {
        axios.get(`${API_BASE_URL}/get-mine-list`).then(res => setMines(res.data));
    }, []);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async () => {
        try {
            // Send empty area/age to trigger Backend Smart Calculation (app.py lines 122-132)
            const payload = isManual ? { ...formData, selected_mine: null } : formData;
            
            await axios.post(`${API_BASE_URL}/update-profile`, payload, { 
                headers: { 'X-User-ID': userId } 
            });
            navigate('/dashboard');
        } catch (err) {
            alert(err.response?.data?.message || "Error setting up profile.");
        }
    };

    return (
        <div style={{ padding: '40px', maxWidth: '600px', margin: '40px auto', background: 'white', borderRadius: '12px', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}>
            <h2 style={{ color: '#2e7d32', marginBottom: '10px' }}>Setup Mine Profile</h2>
            <p style={{ color: '#666', marginBottom: '20px', fontSize: '0.9rem' }}>
                We use this to benchmark your emissions and calculate your carbon sink.
            </p>
            
            <div style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
                <button 
                    onClick={() => setIsManual(false)}
                    style={{ ...tabStyle, background: !isManual ? '#2e7d32' : '#eee', color: !isManual ? 'white' : '#333' }}
                >
                    Select Existing Mine
                </button>
                <button 
                    onClick={() => setIsManual(true)}
                    style={{ ...tabStyle, background: isManual ? '#2e7d32' : '#eee', color: isManual ? 'white' : '#333' }}
                >
                    Create Custom Mine
                </button>
            </div>

            {!isManual ? (
                // OPTION A: REGISTRY MODE
                <div>
                    <label style={labelStyle}>Select Mine from National Registry</label>
                    <select name="selected_mine" onChange={handleChange} style={inputStyle}>
                        <option value="">-- Choose Mine --</option>
                        {mines.map(m => <option key={m} value={m}>{m}</option>)}
                    </select>
                </div>
            ) : (
                // OPTION B: MANUAL MODE WITH SYNTHETIC CALCULATOR
                <div style={{ display: 'grid', gap: '15px' }}>
                    <input name="mine_name" placeholder="Mine Name" onChange={handleChange} style={inputStyle} />
                    
                    <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px'}}>
                        <div>
                            <label style={labelStyle}>State (For Climate Data)</label>
                            <select name="state" onChange={handleChange} style={inputStyle}>
                                <option value="Jharkhand">Jharkhand</option>
                                <option value="Odisha">Odisha</option>
                                <option value="Chhattisgarh">Chhattisgarh</option>
                                <option value="Madhya Pradesh">Madhya Pradesh</option>
                                <option value="Telangana">Telangana</option>
                                <option value="Maharashtra">Maharashtra</option>
                            </select>
                        </div>
                        <div>
                            <label style={labelStyle}>Plantation Type</label>
                            <select name="plant_type" onChange={handleChange} style={inputStyle}>
                                <option value="synthetic">Synthetic (State Avg)</option>
                                <option value="dense_forest">Dense Forest (Sal/Teak)</option>
                                <option value="bamboo">Bamboo</option>
                                <option value="scrub_land">Scrub Land</option>
                            </select>
                        </div>
                    </div>

                    <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px'}}>
                        <input name="production" type="number" placeholder="Production (TPA)" onChange={handleChange} style={inputStyle} />
                        <input name="employees" type="number" placeholder="Employees" onChange={handleChange} style={inputStyle} />
                    </div>
                    
                    {/* AUTO-CALCULATE SECTION */}
                    <div style={{ background: '#e8f5e9', padding: '15px', borderRadius: '8px', border: '1px solid #c8e6c9' }}>
                        <label style={{...labelStyle, color: '#2e7d32'}}>🌱 Green Cover Estimation (Optional)</label>
                        <p style={{ fontSize: '0.8rem', color: '#555', margin: '0 0 10px 0' }}>
                            Leave these blank to automatically estimate based on your <strong>Production</strong> and <strong>State</strong> location standards.
                        </p>
                        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px'}}>
                            <input name="area" type="number" placeholder="Area (Ha) - Optional" onChange={handleChange} style={inputStyle} />
                            <input name="age" type="number" placeholder="Avg Age (Yrs) - Optional" onChange={handleChange} style={inputStyle} />
                        </div>
                    </div>
                </div>
            )}

            <button onClick={handleSubmit} style={btnStyle}>Save Profile</button>
        </div>
    );
};

const inputStyle = { width: '100%', padding: '12px', borderRadius: '6px', border: '1px solid #ccc', boxSizing: 'border-box' };
const tabStyle = { flex: 1, padding: '10px', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' };
const btnStyle = { width: '100%', padding: '14px', marginTop: '20px', background: '#008040', color: 'white', border: 'none', borderRadius: '6px', fontWeight: 'bold', cursor: 'pointer', fontSize: '1rem' };
const labelStyle = { display: 'block', marginBottom: '5px', fontWeight: 'bold', color: '#555', fontSize: '0.9rem' };

export default ProfileSetup;
